  65→export const checkUsernameAvailability = async(username) => {
  66→    const response = await apiRequest(`${BASE_URL}/check-username/${encodeURIComponent(username)}`, {
  67→        method: 'GET',
  68→    });
  69→    if(!response.ok){
  70→        const error = await response.json().catch(() => ({}));
  71→        throw new Error(error?.error || 'failed to check username');
