  76→export const updateUsername = async(token, username) => {
  77→    const headers = {'Content-Type': 'application/json'};
  78→    if(token) headers['Authorization'] = `Bearer ${token}`;
  79→
  80→    const response = await apiRequest(`${BASE_URL}/update-username`, {
  81→        method: 'POST',
  82→        headers: headers,
  83→        body: JSON.stringify({ username })
  84→    });
  85→    if(!response.ok){
  86→        const error = await response.json().catch(() => ({}));
  87→        throw new Error(error?.error || 'failed to update username');
  88→    }
  89→    return await response.json();
